    array( 'text' => 'Do not merely listen to the word, and so deceive yourselves. Do what it says.',                        'ref' => 'Jas. 1:22' ),
    array( 'text' => 'Nothing in all creation is hidden from God\'s sight.',                                                  'ref' => 'Heb. 4:13' ),
    array( 'text' => 'It is God who works in you to will and to act in order to fulfill his good purpose.',                  'ref' => 'Phil. 2:13' ),
    array( 'text' => 'Do everything without grumbling or arguing.',                                                           'ref' => 'Phil. 2:14' ),
    array( 'text' => 'Be completely humble and gentle; be patient, bearing with one another in love.',                       'ref' => 'Eph. 4:2' ),
    array( 'text' => 'Be kind and compassionate to one another, forgiving each other, just as in Christ God forgave you.',   'ref' => 'Eph. 4:32' ),
    array( 'text' => 'So do not throw away your confidence; it will be richly rewarded.',                                    'ref' => 'Heb. 10:35' ),

    array( 'text' => 'We have this hope as an anchor for the soul, firm and secure.',                                        'ref' => 'Heb. 6:19' ),
    array( 'text' => 'Let us hold unswervingly to the hope we profess, for he who promised is faithful.',                    'ref' => 'Heb. 10:23' ),
    array( 'text' => 'Let us run with perseverance the race marked out for us.',                                              'ref' => 'Heb. 12:1' ),
    array( 'text' => 'Fixing our eyes on Jesus, the pioneer and perfecter of faith.',                                        'ref' => 'Heb. 12:2' ),
    array( 'text' => 'The Lord disciplines the one he loves.',                                                                'ref' => 'Heb. 12:6' ),
    array( 'text' => 'Do not forget to show hospitality to strangers, for by so doing some have shown hospitality to angels.', 'ref' => 'Heb. 13:2' ),
    array( 'text' => 'Keep on loving one another as brothers and sisters.',                                                   'ref' => 'Heb. 13:1' ),
    array( 'text' => 'Be content with what you have, because God has said, "Never will I leave you; never will I forsake you."', 'ref' => 'Heb. 13:5' ),
    array( 'text' => 'The Lord is my helper; I will not be afraid. What can mere mortals do to me?',                         'ref' => 'Heb. 13:6' ),
    array( 'text' => 'Now to him who is able to do immeasurably more than all we ask or imagine, to him be glory.',          'ref' => 'Eph. 3:20-21' ),
    array( 'text' => 'He who began a good work in you will carry it on to completion until the day of Christ Jesus.',        'ref' => 'Phil. 1:6' ),
    array( 'text' => 'For to me, to live is Christ and to die is gain.',                                                      'ref' => 'Phil. 1:21' ),
    array( 'text' => 'Do nothing out of selfish ambition or vain conceit. Rather, value others above yourselves.',           'ref' => 'Phil. 2:3' ),
    array( 'text' => 'Not looking to your own interests but each of you to the interests of the others.',                    'ref' => 'Phil. 2:4' ),
    array( 'text' => 'In your relationships with one another, have the same mindset as Christ Jesus.',                       'ref' => 'Phil. 2:5' ),
    array( 'text' => 'Rejoice in the Lord always. I will say it again: Rejoice!',                                             'ref' => 'Phil. 4:4' ),
    array( 'text' => 'Let your gentleness be evident to all. The Lord is near.',                                              'ref' => 'Phil. 4:5' ),
    array( 'text' => 'I have learned the secret of being content in any and every situation.',                               'ref' => 'Phil. 4:11' ),
    array( 'text' => 'And the peace of God, which transcends all understanding, will guard your hearts and minds.',          'ref' => 'Phil. 4:7' ),
    array( 'text' => 'Finally, brothers and sisters, whatever is true, whatever is noble, whatever is right — think about such things.', 'ref' => 'Phil. 4:8' ),
    array( 'text' => 'And my God will meet all your needs according to the riches of his glory in Christ Jesus.',            'ref' => 'Phil. 4:19' ),
    array( 'text' => 'Strengthened with all power according to his glorious might so that you may have great endurance.',    'ref' => 'Col. 1:11' ),
    array( 'text' => 'Giving joyful thanks to the Father who has qualified you to share in the inheritance of his holy people.', 'ref' => 'Col. 1:12' ),
    array( 'text' => 'Christ in you, the hope of glory.',                                                                     'ref' => 'Col. 1:27' ),
    array( 'text' => 'So then, just as you received Christ Jesus as Lord, continue to live your lives in him.',              'ref' => 'Col. 2:6' ),
    array( 'text' => 'Since, then, you have been raised with Christ, set your hearts on things above.',                      'ref' => 'Col. 3:1' ),
    array( 'text' => 'Clothe yourselves with compassion, kindness, humility, gentleness and patience.',                      'ref' => 'Col. 3:12' ),
    array( 'text' => 'And over all these virtues put on love, which binds them all together in perfect unity.',              'ref' => 'Col. 3:14' ),
    array( 'text' => 'Let the peace of Christ rule in your hearts.',                                                          'ref' => 'Col. 3:15' ),
    array( 'text' => 'Let the message of Christ dwell among you richly.',                                                     'ref' => 'Col. 3:16' ),

    array( 'text' => 'And whatever you do, whether in word or deed, do it all in the name of the Lord Jesus.',               'ref' => 'Col. 3:17' ),
    array( 'text' => 'Devote yourselves to prayer, being watchful and thankful.',                                             'ref' => 'Col. 4:2' ),
    array( 'text' => 'Let your conversation be always full of grace, seasoned with salt.',                                   'ref' => 'Col. 4:6' ),
    array( 'text' => 'May the Lord make your love increase and overflow for each other and for everyone else.',               'ref' => '1 Thess. 3:12' ),
    array( 'text' => 'For the Lord himself will come down from heaven, with a loud command, with the voice of the archangel.', 'ref' => '1 Thess. 4:16' ),
    array( 'text' => 'For the Spirit God gave us does not make us timid, but gives us power, love and self-discipline.',     'ref' => '2 Tim. 1:7' ),
    array( 'text' => 'I have fought the good fight, I have finished the race, I have kept the faith.',                       'ref' => '2 Tim. 4:7' ),
    array( 'text' => 'Now there is in store for me the crown of righteousness.',                                              'ref' => '2 Tim. 4:8' ),
    array( 'text' => 'For the grace of God has appeared that offers salvation to all people.',                                'ref' => 'Titus 2:11' ),
    array( 'text' => 'He who began a good work in you will carry it on to completion.',                                      'ref' => 'Phil. 1:6' ),
    array( 'text' => 'I want to know Christ — yes, to know the power of his resurrection.',                                  'ref' => 'Phil. 3:10' ),
    array( 'text' => 'Forgetting what is behind and straining toward what is ahead.',                                        'ref' => 'Phil. 3:13' ),
    array( 'text' => 'I press on toward the goal to win the prize for which God has called me heavenward.',                  'ref' => 'Phil. 3:14' ),
    array( 'text' => 'But our citizenship is in heaven, and we eagerly await a Savior from there.',                          'ref' => 'Phil. 3:20' ),
    array( 'text' => 'Ask and it will be given to you; seek and you will find; knock and the door will be opened.',          'ref' => 'Mt. 7:7' ),
    array( 'text' => 'For everyone who asks receives; the one who seeks finds.',                                              'ref' => 'Mt. 7:8' ),
    array( 'text' => 'Do to others what you would have them do to you.',                                                     'ref' => 'Mt. 7:12' ),
    array( 'text' => 'Not everyone who says to me, "Lord, Lord," will enter the kingdom of heaven, but only the one who does the will of my Father.', 'ref' => 'Mt. 7:21' ),
    array( 'text' => 'Everyone who hears these words of mine and puts them into practice is like a wise man.',               'ref' => 'Mt. 7:24' ),
    array( 'text' => 'What God has joined together, let no one separate.',                                                   'ref' => 'Mk. 10:9' ),
    array( 'text' => 'Love the Lord your God with all your heart and with all your soul and with all your mind.',            'ref' => 'Mt. 22:37' ),
    array( 'text' => 'The second is this: Love your neighbor as yourself.',                                                  'ref' => 'Mt. 22:39' ),
    array( 'text' => 'Go into all the world and preach the gospel to all creation.',                                         'ref' => 'Mk. 16:15' ),
    array( 'text' => 'And surely I am with you always, to the very end of the age.',                                        'ref' => 'Mt. 28:20' ),
    array( 'text' => 'All authority in heaven and on earth has been given to me.',                                           'ref' => 'Mt. 28:18' ),
    array( 'text' => 'Therefore go and make disciples of all nations.',                                                      'ref' => 'Mt. 28:19' ),
    array( 'text' => 'Wait for the Lord; be strong and take heart and wait for the Lord.',                                   'ref' => 'Ps. 27:14' ),
    array( 'text' => 'The Lord will march out like a champion, like a warrior he will stir up his zeal.',                   'ref' => 'Is. 42:13' ),
    array( 'text' => 'Even though I walk through the darkest valley, I will fear no evil.',                                  'ref' => 'Ps. 23:4' ),
    array( 'text' => 'Your rod and your staff, they comfort me.',                                                             'ref' => 'Ps. 23:4' ),

    array( 'text' => 'You anoint my head with oil; my cup overflows.',                                                        'ref' => 'Ps. 23:5' ),
    array( 'text' => 'Surely your goodness and love will follow me all the days of my life.',                                'ref' => 'Ps. 23:6' ),
    array( 'text' => 'And I will dwell in the house of the Lord forever.',                                                   'ref' => 'Ps. 23:6' ),
    array( 'text' => 'The Lord is my rock, my fortress and my deliverer.',                                                   'ref' => 'Ps. 18:2' ),
    array( 'text' => 'I call out to my God Most High, to God who vindicates me.',                                            'ref' => 'Ps. 57:2' ),
    array( 'text' => 'The Lord upholds all who fall and lifts up all who are bowed down.',                                   'ref' => 'Ps. 145:14' ),
    array( 'text' => 'The Lord is trustworthy in all he promises and faithful in all he does.',                              'ref' => 'Ps. 145:13' ),
    array( 'text' => 'The Lord watches over all who love him, but all the wicked he will destroy.',                          'ref' => 'Ps. 145:20' ),
    array( 'text' => 'My mouth will speak in praise of the Lord. Let every creature praise his holy name.',                  'ref' => 'Ps. 145:21' ),
    array( 'text' => 'Praise the Lord, my soul. I will praise the Lord all my life.',                                        'ref' => 'Ps. 146:2' ),
    array( 'text' => 'The Lord reigns forever, your God, O Zion, for all generations.',                                     'ref' => 'Ps. 146:10' ),
    array( 'text' => 'He determines the number of the stars and calls them each by name.',                                   'ref' => 'Ps. 147:4' ),
    array( 'text' => 'Great is our Lord and mighty in power; his understanding has no limit.',                               'ref' => 'Ps. 147:5' ),
    array( 'text' => 'The Lord delights in those who fear him, who put their hope in his unfailing love.',                   'ref' => 'Ps. 147:11' ),
    array( 'text' => 'He sends his command to the earth; his word runs swiftly.',                                            'ref' => 'Ps. 147:15' ),
    array( 'text' => 'Let them praise the name of the Lord, for his name alone is exalted.',                                 'ref' => 'Ps. 148:13' ),
    array( 'text' => 'Sing to the Lord a new song, his praise in the assembly of his faithful people.',                     'ref' => 'Ps. 149:1' ),
    array( 'text' => 'For the Lord takes delight in his people; he crowns the humble with victory.',                         'ref' => 'Ps. 149:4' ),
    array( 'text' => 'Praise God in his sanctuary; praise him in his mighty heavens.',                                       'ref' => 'Ps. 150:1' ),
    array( 'text' => 'Let everything that has breath praise the Lord.',                                                       'ref' => 'Ps. 150:6' ),
    array( 'text' => '"Not by might nor by power, but by my Spirit," says the Lord Almighty.',                               'ref' => 'Zech. 4:6' ),
    array( 'text' => 'The Lord Almighty is with us; the God of Jacob is our fortress.',                                      'ref' => 'Ps. 46:7' ),
    array( 'text' => 'Be still, and know that I am God.',                                                                     'ref' => 'Ps. 46:10' ),
    array( 'text' => 'A cheerful heart is good medicine, but a crushed spirit dries up the bones.',                         'ref' => 'Prov. 17:22' ),
    array( 'text' => 'Better a dish of vegetables with love than a fattened calf with hatred.',                              'ref' => 'Prov. 15:17' ),
    array( 'text' => 'A gentle answer turns away wrath, but a harsh word stirs up anger.',                                   'ref' => 'Prov. 15:1' ),
    array( 'text' => 'A sluggard says, "There\'s a lion in the road, a fierce lion roaming the streets!"',                  'ref' => 'Prov. 26:13' ),
    array( 'text' => 'Like a city whose walls are broken through is a person who lacks self-control.',                       'ref' => 'Prov. 25:28' ),
    array( 'text' => 'Whoever is not with me is against me.',                                                                 'ref' => 'Mt. 12:30' ),
    array( 'text' => 'No one can serve two masters.',                                                                         'ref' => 'Mt. 6:24' ),

    array( 'text' => 'Therefore do not worry about tomorrow, for tomorrow will worry about itself.',                         'ref' => 'Mt. 6:34' ),
    array( 'text' => 'It is more blessed to give than to receive.',                                                           'ref' => 'Acts 20:35' ),
    array( 'text' => 'Faith without deeds is dead.',                                                                          'ref' => 'Jas. 2:26' ),
    array( 'text' => 'Humble yourselves before the Lord, and he will lift you up.',                                          'ref' => 'Jas. 4:10' ),
    array( 'text' => '"God opposes the proud but shows favor to the humble."',                                                'ref' => 'Jas. 4:6' ),
    array( 'text' => 'With the Lord a day is like a thousand years, and a thousand years are like a day.',                   'ref' => '2 Pet. 3:8' ),
    array( 'text' => 'The Lord is not slow in keeping his promise, as some understand slowness.',                            'ref' => '2 Pet. 3:9' ),
    array( 'text' => 'Sanctify them by the truth; your word is truth.',                                                       'ref' => 'Jn. 17:17' ),
    array( 'text' => 'As the Father has sent me, I am sending you.',                                                          'ref' => 'Jn. 20:21' ),
    array( 'text' => 'Receive the Holy Spirit.',                                                                               'ref' => 'Jn. 20:22' ),
    array( 'text' => 'My Lord and my God!',                                                                                    'ref' => 'Jn. 20:28' ),
    array( 'text' => 'Blessed are those who have not seen and yet have believed.',                                            'ref' => 'Jn. 20:29' ),
    array( 'text' => 'Feed my sheep.',                                                                                         'ref' => 'Jn. 21:17' ),
    array( 'text' => 'Praise and glory and wisdom and thanks and honor and power and strength be to our God.',               'ref' => 'Rev. 7:12' ),
    array( 'text' => 'Here I am! I stand at the door and knock. If anyone hears my voice and opens the door, I will come in.', 'ref' => 'Rev. 3:20' ),
    array( 'text' => 'To the one who is victorious, I will give the right to sit with me on my throne.',                    'ref' => 'Rev. 3:21' ),
    array( 'text' => 'Do not be afraid. I am the First and the Last.',                                                       'ref' => 'Rev. 1:17' ),
    array( 'text' => '"He will wipe every tear from their eyes. There will be no more death or mourning or crying or pain."', 'ref' => 'Rev. 21:4' ),
    array( 'text' => '"I am making everything new!"',                                                                          'ref' => 'Rev. 21:5' ),
    array( 'text' => 'I am the Alpha and the Omega, the Beginning and the End.',                                              'ref' => 'Rev. 21:6' ),
    array( 'text' => 'The Spirit and the bride say, "Come!" And let the one who is thirsty come.',                           'ref' => 'Rev. 22:17' ),
    array( 'text' => 'He who testifies to these things says, "Yes, I am coming soon." Amen. Come, Lord Jesus.',              'ref' => 'Rev. 22:20' ),
    array( 'text' => 'Blessed is she who has believed that the Lord would fulfill his promises to her.',                     'ref' => 'Lk. 1:45' ),
    array( 'text' => 'My soul glorifies the Lord and my spirit rejoices in God my Savior.',                                  'ref' => 'Lk. 1:46-47' ),
    array( 'text' => 'For the Lord Most High is awesome, the great King over all the earth.',                                'ref' => 'Ps. 47:2' ),
    array( 'text' => 'God reigns over the nations; God is seated on his holy throne.',                                       'ref' => 'Ps. 47:8' ),
    array( 'text' => 'The earth is the Lord\'s, and everything in it.',                                                       'ref' => 'Ps. 24:1' ),
    array( 'text' => 'Who may ascend the mountain of the Lord? The one who has clean hands and a pure heart.',               'ref' => 'Ps. 24:3-4' ),
    array( 'text' => 'The Lord strong and mighty, the Lord mighty in battle.',                                               'ref' => 'Ps. 24:8' ),
    array( 'text' => 'The Lord Almighty — he is the King of glory.',                                                         'ref' => 'Ps. 24:10' ),

    array( 'text' => 'Blessed is the nation whose God is the Lord.',                                                          'ref' => 'Ps. 33:12' ),
    array( 'text' => 'The eyes of the Lord are on the righteous, and his ears are attentive to their cry.',                  'ref' => 'Ps. 34:15' ),
    array( 'text' => 'The Lord will rescue his servants; no one who takes refuge in him will be condemned.',                 'ref' => 'Ps. 34:22' ),
    array( 'text' => 'A good man brings good things out of the good stored up in his heart.',                                'ref' => 'Lk. 6:45' ),
    array( 'text' => 'Love your enemies, do good to those who hate you.',                                                     'ref' => 'Lk. 6:27' ),
    array( 'text' => 'Do to others as you would have them do to you.',                                                       'ref' => 'Lk. 6:31' ),
    array( 'text' => 'Be merciful, just as your Father is merciful.',                                                         'ref' => 'Lk. 6:36' ),
    array( 'text' => 'Give, and it will be given to you. A good measure, pressed down, shaken together and running over.',  'ref' => 'Lk. 6:38' ),
    array( 'text' => 'Whoever finds their life will lose it, and whoever loses their life for my sake will find it.',        'ref' => 'Mt. 10:39' ),
    array( 'text' => 'Do not be afraid of those who kill the body but cannot kill the soul.',                                'ref' => 'Mt. 10:28' ),
    array( 'text' => 'And even the very hairs of your head are all numbered.',                                               'ref' => 'Mt. 10:30' ),
    array( 'text' => 'Ask and it will be given to you; seek and you will find; knock and the door will be opened.',         'ref' => 'Lk. 11:9' ),
    array( 'text' => 'Are you not much more valuable than birds?',                                                           'ref' => 'Mt. 6:26' ),
    array( 'text' => 'Be perfect, therefore, as your heavenly Father is perfect.',                                           'ref' => 'Mt. 5:48' ),
    array( 'text' => 'Let your light shine before others, that they may see your good deeds and glorify your Father.',      'ref' => 'Mt. 5:16' ),
    array( 'text' => 'All the Law and the Prophets hang on these two commandments.',                                         'ref' => 'Mt. 22:40' ),
    array( 'text' => 'For many are invited, but few are chosen.',                                                             'ref' => 'Mt. 22:14' ),
    array( 'text' => 'Create in me a pure heart, O God, and renew a steadfast spirit within me.',                           'ref' => 'Ps. 51:10' ),
    array( 'text' => 'Restore to me the joy of your salvation and grant me a willing spirit.',                               'ref' => 'Ps. 51:12' ),
    array( 'text' => 'My sacrifice, O God, is a broken spirit; a broken and contrite heart you, God, will not despise.',    'ref' => 'Ps. 51:17' ),
    array( 'text' => 'You, Lord, are forgiving and good, abounding in love to all who call to you.',                        'ref' => 'Ps. 86:5' ),
    array( 'text' => 'Teach me your way, Lord, that I may rely on your faithfulness.',                                       'ref' => 'Ps. 86:11' ),
    array( 'text' => 'I will instruct you and teach you in the way you should go; I will counsel you with my loving eye.',  'ref' => 'Ps. 32:8' ),
    array( 'text' => 'Many are the woes of the wicked, but the Lord\'s unfailing love surrounds the one who trusts in him.', 'ref' => 'Ps. 32:10' ),
    array( 'text' => 'May your unfailing love be with us, Lord, even as we put our hope in you.',                           'ref' => 'Ps. 33:22' ),
    array( 'text' => 'The Lord foils the plans of the nations; he thwarts the purposes of the peoples.',                    'ref' => 'Ps. 33:10' ),
    array( 'text' => 'But the plans of the Lord stand firm forever, the purposes of his heart through all generations.',    'ref' => 'Ps. 33:11' ),
    array( 'text' => 'Wait for the Lord; be strong and take heart and wait for the Lord.',                                   'ref' => 'Ps. 27:14' ),
    array( 'text' => 'With God we will gain the victory, and he will trample down our enemies.',                             'ref' => 'Ps. 60:12' ),
    array( 'text' => 'In God I trust and am not afraid. What can man do to me?',                                            'ref' => 'Ps. 56:11' ),
    array( 'text' => 'With God we will gain the victory.',                                                                    'ref' => 'Ps. 108:13' ),
    array( 'text' => 'I will sing of the Lord\'s great love forever.',                                                       'ref' => 'Ps. 89:1' ),
    array( 'text' => 'Blessed are all who fear the Lord, who walk in obedience to him.',                                    'ref' => 'Ps. 128:1' ),
    array( 'text' => 'Love and faithfulness meet together; righteousness and peace kiss each other.',                        'ref' => 'Ps. 85:10' ),
    array( 'text' => 'For the Lord gives wisdom; from his mouth come knowledge and understanding.',                          'ref' => 'Prov. 2:6' ),
);
